typedef float fp;

__kernel void extract_kernel(long d_Ne, __global fp *d_I) {
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2) {
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int d_blocks) {
    (void)d_Ne;
    (void)d_blocks;

    const int tx = (int)get_local_id(0);
    const int bx = (int)get_group_id(0);
    const int lsize = (int)get_local_size(0);
    const int gsize = (int)get_num_groups(0);

    if (tx == 0) {
        int nf = lsize - (gsize * lsize - (int)d_no);
        int count = (bx == (gsize - 1)) ? nf : lsize;
        if (count < 0) count = 0;
        if (count > lsize) count = lsize;

        fp sum = 0.0f;
        fp sum2 = 0.0f;

        int start = bx * lsize;
        for (int t = 0; t < count; t++) {
            int idx = start + t;
            if ((long)idx < d_no) {
                fp a = d_sums[idx * d_mul];
                fp b = d_sums2[idx * d_mul];
                sum += a;
                sum2 += b;
            }
        }

        int out = bx * d_mul * lsize;
        d_sums[out] = sum;
        d_sums2[out] = sum2;
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I) {
    (void)lambda;
    long ei = (long)get_global_id(0);
    if (ei < Ne) {
        int i = (int)(ei / (long)Nc);
        int j = (int)(ei - (long)i * (long)Nc);

        fp Jc = d_I[ei];

        fp dN = d_I[(long)iN[i] * (long)Nc + j] - Jc;
        fp dS = d_I[(long)iS[i] * (long)Nc + j] - Jc;
        fp dW = d_I[(long)i * (long)Nc + jW[j]] - Jc;
        fp dE = d_I[(long)i * (long)Nc + jE[j]] - Jc;

        d_dN[ei] = dN;
        d_dS[ei] = dS;
        d_dW[ei] = dW;
        d_dE[ei] = dE;

        fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        fp L = (dN + dS + dW + dE) / Jc;

        fp num = (fp)0.5f * G2 - (fp)0.0625f * (L * L);
        fp den = (fp)1.0f + (fp)0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
        fp c = (fp)1.0f / ((fp)1.0f + den);

        if (c < (fp)0.0f) c = (fp)0.0f;
        else if (c > (fp)1.0f) c = (fp)1.0f;

        d_c[ei] = c;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I) {
    (void)Nr;
    (void)iN;
    (void)jW;

    long ei = (long)get_global_id(0);
    if (ei < Ne) {
        int i = (int)(ei / (long)Nc);
        int j = (int)(ei - (long)i * (long)Nc);

        fp cN = d_c[ei];
        fp cS = d_c[(long)iS[i] * (long)Nc + j];
        fp cW = d_c[ei];
        fp cE = d_c[(long)i * (long)Nc + jE[j]];

        fp D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];
        d_I[ei] = d_I[ei] + (fp)0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne, __global fp *d_I) {
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
